import { ipcMain } from 'electron';
import { IPC_CHANNELS, GetMetricsSchema, ApiResult, ServerMetrics, QuickMetrics } from './types';
import { metricsService } from '../services/MetricsService';

export function registerMetricsHandlers() {
  /**
   * Get quick metrics - Stage 1 of progressive loading.
   * Returns essential CPU/Memory/Disk/Network data in a single fast SSH call.
   */
  ipcMain.handle(IPC_CHANNELS.METRICS_GET_QUICK, async (_event, input): Promise<ApiResult<QuickMetrics>> => {
    try {
      const { serverId } = GetMetricsSchema.parse(input);
      const metrics = await metricsService.getQuickMetrics(serverId);
      return { success: true, data: metrics };
    } catch (error) {
      console.error('Error fetching quick metrics:', error);
      return { success: false, error: String(error) };
    }
  });

  /**
   * Get full metrics - Stage 2 of progressive loading.
   * Returns complete metrics including system info, health, alerts, and filesystems.
   */
  ipcMain.handle(IPC_CHANNELS.METRICS_GET, async (_event, input): Promise<ApiResult<ServerMetrics>> => {
    try {
      const { serverId } = GetMetricsSchema.parse(input);
      const metrics = await metricsService.getMetrics(serverId);
      return { success: true, data: metrics };
    } catch (error) {
      console.error('Error fetching server metrics:', error);
      return { success: false, error: String(error) };
    }
  });
}
